// ============================================================
// About.jsx
// "About Me" section with a botanical card and interest chips.
// Uses IntersectionObserver for a fade-in-up on scroll.
// ============================================================

import React, { useEffect, useRef } from 'react';
import '../styles/sections.css';

// Reusable hook: adds .visible class when element enters viewport
const useReveal = (threshold = 0.15) => {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) { el.classList.add('visible'); observer.disconnect(); } },
      { threshold }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [threshold]);
  return ref;
};

// Interest chip data
const INTERESTS = [
  '🌿 Web Development',
  '⚡ React.js',
  '🎨 Creative Coding',
  '🚀 Entrepreneurship',
  '🎮 Game Dev',
  '💡 Problem Solving',
];

const About = () => {
  const leftRef  = useReveal();
  const rightRef = useReveal();

  return (
    <section id="about" className="about section">
      <div className="container">
        <div className="about__grid">

          {/* Text side */}
          <div
            ref={leftRef}
            style={{
              opacity: 0,
              transform: 'translateY(30px)',
              transition: 'opacity 0.7s ease 0.1s, transform 0.7s ease 0.1s',
            }}
            className="about__text reveal-el"
          >
            <span className="section-label">About Me</span>
            <h2 className="section-title">Building things<br /><em>with purpose</em></h2>

            <div className="about__body">
              <p>
                Hi! I'm <strong>Khushi Bhavsar</strong>, a Grade 12 student with a deep curiosity for how
                software can solve real problems and spark creativity. I'm drawn to the intersection of
                technology, design, and entrepreneurship.
              </p>
              <p>
                I love crafting <strong>web applications</strong> that are both functional and beautiful —
                from interactive games built with p5.js to full platforms that empower creators. Every
                project is a chance to learn something new.
              </p>
              <p>
                When I'm not coding, you'll find me exploring ideas at the edge of technology and
                business, dreaming up the next thing to build.
              </p>
            </div>

            {/* Interest chips */}
            <div className="about__chips">
              {INTERESTS.map((interest) => (
                <span key={interest} className="about__chip">{interest}</span>
              ))}
            </div>
          </div>

          {/* Visual / card side */}
          <div
            ref={rightRef}
            style={{
              opacity: 0,
              transform: 'translateY(30px)',
              transition: 'opacity 0.7s ease 0.25s, transform 0.7s ease 0.25s',
            }}
            className="about__visual reveal-el"
          >
            <div className="about__card">
              {/* Leaf pattern watermark */}
              <svg
                className="about__card-leaf-bg"
                viewBox="0 0 360 360"
                xmlns="http://www.w3.org/2000/svg"
                aria-hidden="true"
              >
                {[...Array(6)].map((_, i) => (
                  <ellipse
                    key={i}
                    cx={60 + (i % 3) * 120}
                    cy={80 + Math.floor(i / 3) * 180}
                    rx="38"
                    ry="65"
                    fill="#3d7a32"
                    transform={`rotate(${i * 30 - 15}, ${60 + (i % 3) * 120}, ${80 + Math.floor(i / 3) * 180})`}
                  />
                ))}
              </svg>

              <span className="about__card-emoji" role="img" aria-label="Seedling">🌱</span>
              <h3>Khushi Bhavsar</h3>
              <p>Grade 12 · Software Engineering & CS</p>

              <div style={{ marginTop: '1.5rem', textAlign: 'left' }}>
                {[
                  { icon: '📍', text: 'Canada' },
                  { icon: '🎓', text: 'Grade 12 Student' },
                  { icon: '💻', text: 'React · JS · HTML · CSS' },
                  { icon: '🌿', text: 'Nature-inspired design' },
                ].map(({ icon, text }) => (
                  <div
                    key={text}
                    style={{
                      display: 'flex', alignItems: 'center', gap: '0.6rem',
                      marginBottom: '0.6rem', fontSize: '0.88rem',
                      color: 'var(--clr-text-muted)',
                    }}
                  >
                    <span>{icon}</span>
                    <span>{text}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Inline reveal style: toggled by IntersectionObserver above */}
      <style>{`
        .reveal-el.visible {
          opacity: 1 !important;
          transform: translateY(0) !important;
        }
      `}</style>
    </section>
  );
};

export default About;
